import type { NextConfig } from "next";

const nextConfig: NextConfig = {};

export default nextConfig;

import { createPostAction } from './actions';
import { getPosts } from './posts-data';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main style={{ maxWidth: 720, margin: '48px auto', padding: '0 24px' }}>
      <h1>Posts</h1>
      <p>Create a post. The list is cached with the <code>posts</code> tag.</p>

      <form action={createPostAction} style={{ display: 'grid', gap: 12, marginBlock: 24 }}>
        <input
          name="title"
          placeholder="Post title"
          aria-label="Post title"
          required
          style={{ padding: 12, fontSize: 16 }}
        />
        <textarea
          name="content"
          placeholder="Post content"
          aria-label="Post content"
          required
          rows={5}
          style={{ padding: 12, fontSize: 16, resize: 'vertical' }}
        />
        <button type="submit" style={{ width: 'fit-content', padding: '10px 16px' }}>
          Create post
        </button>
      </form>

      <section>
        <h2>Cached list</h2>
        <ul style={{ display: 'grid', gap: 16, paddingLeft: 18 }}>
          {posts.map((post) => (
            <li key={post.id}>
              <h3 style={{ marginBottom: 4 }}>{post.title}</h3>
              <p style={{ margin: 0 }}>{post.content}</p>
            </li>
          ))}
        </ul>
      </section>
    </main>
  );
}

