import { cacheTag } from 'next/cache';

export type Post = {
  id: string;
  title: string;
  content: string;
  createdAt: string;
};

const posts: Post[] = [
  {
    id: 'welcome',
    title: 'Welcome post',
    content: 'This is the initial cached post list.',
    createdAt: new Date().toISOString()
  }
];

export async function getPosts() {
  'use cache';

  cacheTag('posts');

  return [...posts].sort(
    (a, b) => Date.parse(b.createdAt) - Date.parse(a.createdAt)
  );
}

export function createPost(input: { title: string; content: string }) {
  const post: Post = {
    id: crypto.randomUUID(),
    title: input.title,
    content: input.content,
    createdAt: new Date().toISOString()
  };

  posts.unshift(post);

  return post;
}

